'use client';

import Script from 'next/script';
import { siteConfig } from '../../site.config';

export default function Analytics() {
  const { providers, umami, plausible, google } = siteConfig.analytics;

  if (!providers || providers.length === 0) return null;

  return (
    <>
      {providers.includes('umami') && umami.websiteId && (
        <Script
          src={umami.src}
          data-website-id={umami.websiteId}
          strategy="afterInteractive"
        />
      )}

      {providers.includes('plausible') && plausible.domain && (
        <Script
          src={plausible.src}
          data-domain={plausible.domain}
          strategy="afterInteractive"
        />
      )}

      {providers.includes('google') && google.measurementId && (
        <>
          <Script
            src={`https://www.googletagmanager.com/gtag/js?id=${google.measurementId}`}
            strategy="afterInteractive"
          />
          <Script id="google-analytics" strategy="afterInteractive">
            {`
              window.dataLayer = window.dataLayer || [];
              function gtag(){dataLayer.push(arguments);}
              gtag('js', new Date());
              gtag('config', '${google.measurementId}');
            `}
          </Script>
        </>
      )}
    </>
  );
}

import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  /* config options here */
  reactCompiler: true,
  // Next.js default is false (slug.html), but we use true (slug/index.html)
  // for two reasons:
  //   1. Co-located assets: posts can have a slug/images/ directory alongside
  //      slug/index.html. With false, slug.html and slug/ conflict on some
  //      static hosts and cause 403 errors.
  //   2. Nginx cosmetics: nginx.conf strips the trailing slash via redirect
  //      (/slug/ → /slug) so the visible URL matches the false convention
  //      without changing the export format.
  trailingSlash: true,
  output: "export",
  images: {
    loader: "custom",
    imageSizes: [16, 32, 48, 64, 96, 128, 256, 384],
    deviceSizes: [640, 750, 828, 1080, 1200, 1920, 2048, 3840],
  },
  transpilePackages: ["next-image-export-optimizer"],
  env: {
    nextImageExportOptimizer_imageFolderPath: "public",
    nextImageExportOptimizer_exportFolderPath: "out",
    nextImageExportOptimizer_quality: "75",
    nextImageExportOptimizer_storePicturesInWEBP: "true",
    nextImageExportOptimizer_generateAndUseBlurImages: "true",
  },
};

export default nextConfig;

